class Solution:
  def solve(self, nums: list[int]) -> list[int]:
    for i in range(len(nums)):
      for j in range(len(nums) - 1):
        if nums[j] > nums[j + 1]:
          temp = nums[j]
          nums[j] = nums[j + 1]
          nums[j + 1] = temp
      for k in range(len(nums) - 1, 0, -1):
        if nums[k - 1] > nums[k]:
          temp = nums[k - 1]
          nums[k - 1] = nums[k]
          nums[k] = temp
    return nums

def main():
  n = int(input())
  nums = list(map(int, input().split()))
  solution = Solution()
  print(' '.join(map(str, solution.solve(nums))))

