#include <iostream>
#include <vector>
using namespace std;
class Solution {
 public:
  vector<int> solve(vector<int>& nums) {
    for (int i = 0; i < nums.size(); i++) {
      for (int j = 0; j < nums.size() - 1; j++) {
        if (nums[j] > nums[j + 1]) {
          int temp = nums[j];
          nums[j] = nums[j + 1];
          nums[j + 1] = temp;
        }
      }
      for (int k = nums.size() - 1; k > 0; k--) {
        if (nums[k - 1] > nums[k]) {
          int temp = nums[k - 1];
          nums[k - 1] = nums[k];
          nums[k] = temp;
        }
      }
    }
    return nums;
  }
};

